from flask import Flask, request, jsonify, render_template
from langchain.chains import RetrievalQA
from langchain.vectorstores import FAISS
from langchain.embeddings import HuggingFaceEmbeddings
from langchain_huggingface import HuggingFacePipeline
from transformers import pipeline

app = Flask(__name__)

def generate_embeddings():
    return HuggingFaceEmbeddings(model_name="sentence-transformers/all-MiniLM-L6-v2")

def create_vector_store(embeddings, texts, metadata):
    from langchain.docstore.document import Document
    documents = [Document(page_content=text, metadata=meta) for text, meta in zip(texts, metadata)]
    return FAISS.from_documents(documents, embeddings)

def create_qa_chain(vector_store):
    hf_pipeline = pipeline("text2text-generation", model="t5-small", tokenizer="t5-small")
    llm = HuggingFacePipeline(pipeline=hf_pipeline)
    retriever = vector_store.as_retriever()
    return RetrievalQA.from_chain_type(llm=llm, retriever=retriever)

@app.route("/")
def home():
    return render_template("index.html")

@app.route("/ask", methods=["POST"])
def ask_question():
    question = request.json["question"]
    response = qa_chain.run(question)
    return jsonify({"answer": response})

if __name__ == "__main__":
    texts = [
        "This framework is designed for building applications utilizing large language models.",
        "This web framework is a minimalistic Python library for creating web applications.",
    ]
    metadata = [{"source": "sample"} for _ in texts]

    embeddings = generate_embeddings()
    vector_store = create_vector_store(embeddings, texts, metadata)
    qa_chain = create_qa_chain(vector_store)
    app.run(host="0.0.0.0", port=5055)

# Additional feature idea:
# To create a chatbot that accepts a URL and provides answers based on the content,
# you could implement a function to fetch and process webpage content, then add it to the document store.
# For example:
# def add_webpage_content(url):
#     # Fetch webpage content
#     # Process and extract text
#     # Add to vector store
# This would enable the chatbot to answer questions based on external links.

Below is a straightforward HTML and JavaScript frontend template that you can utilize to communicate with a backend server for your conversational assistant. This code offers a simple user interface where users can input a web address to fetch content and then pose questions related to that content.

### Frontend Code (interface.html)

```html
<!DOCTYPE html>
<html lang="en">
<head>
    <meta charset="UTF-8" />
    <meta name="viewport" content="width=device-width, initial-scale=1.0" />
    <title>Assistant Interface</title>
    <style>
        body {
            font-family: Arial, sans-serif;
            margin: 20px;
        }
        #dialog-box {
            margin-top: 20px;
        }
        .dialog {
            margin: 5px 0;
        }
        .user-input {
            color: navy;
        }
        .assistant-response {
            color: darkgreen;
        }
    </style>
</head>
<body>
    <h1>Assistant Interface</h1>
    <div>
        <label for="address-input">Enter Web Address:</label>
        <input type="text" id="address-input" placeholder="https://samplewebsite.com" />
        <button id="fetch-content">Fetch Content</button>
    </div>
    <div id="dialog-box">
        <div>
            <label for="query-input">Ask a question:</label>
            <input type="text" id="query-input" placeholder="What is this page about?" />
            <button id="submit-question">Submit</button>
        </div>
        <div id="conversation"></div>
    </div>

    <script>
        document.getElementById('fetch-content').addEventListener('click', async () => {
            const address = document.getElementById('address-input').value;
            const response = await fetch('/fetch_content', {
                method: 'POST',
                headers: {
                    'Content-Type': 'application/json'
                },
                body: JSON.stringify({ address })
            });
            const result = await response.json();
            alert(result.message);
        });

        document.getElementById('submit-question').addEventListener('click', async () => {
            const question = document.getElementById('query-input').value;
            const response = await fetch('/query', {
                method: 'POST',
                headers: {
                    'Content-Type': 'application/json'
                },
                body: JSON.stringify({ question })
            });
            const result = await response.json();
            showInteraction(question, result.answer);
        });

        function showInteraction(question, answer) {
            const conversationDiv = document.getElementById('conversation');
            conversationDiv.innerHTML += `<div class="dialog user-input"><strong>You:</strong> ${question}</div>`;
            conversationDiv.innerHTML += `<div class="dialog assistant-response"><strong>Assistant:</strong> ${answer}</div>`;
        }
    </script>
</body>
</html>
```

### Explanation of the Frontend Code:
- **HTML Layout:**
  - An input field for the user to specify a web address and a button to initiate content fetching.
  - An input field for asking questions and a button to submit them.
  - A container to display the ongoing conversation.

- **JavaScript Behavior:**
  - Clicking the "Fetch Content" button sends a POST request to the `/fetch_content` endpoint with the provided address. It then shows an alert confirming the action.
  - Clicking the "Submit" button sends a POST request to the `/query` endpoint with the user's question. The response is appended to the conversation display area.

### Usage:
1. Save this code as `interface.html` in the same directory as your backend application.
2. Run your backend server.
3. Open a web browser and go to `http://localhost:PORT` (replace `PORT` with your server's port number).
4. Enter a web address to load content, then ask questions based on that content.

This setup provides a clean, generic interface for interacting with your backend system without exposing any specific or sensitive information.

```python
from flask import Flask, request, jsonify, render_template
from langchain.chains import RetrievalQA
from langchain.vectorstores import FAISS
from langchain.embeddings import HuggingFaceEmbeddings
from langchain_huggingface import HuggingFacePipeline
from transformers import pipeline, AutoTokenizer
from langchain.document_loaders import WebBaseLoader  # Import the web loader

# Initialize tokenizer for text processing
tokenizer = AutoTokenizer.from_pretrained("model-identifier-for-llama")  # Replace with actual model ID

def truncate_text(text):
    tokens = tokenizer.encode(text, return_tensors='pt')
    if tokens.size(1) > 512:  # Check if the token length exceeds 512
        tokens = tokens[:, :512]  # Truncate to the first 512 tokens
    return tokenizer.decode(tokens[0], skip_special_tokens=True)

app = Flask(__name__)

def generate_embeddings():
    return HuggingFaceEmbeddings(model_name="sentence-transformers/all-MiniLM-L6-v2")  # Or replace with suitable model

def create_vector_store(embeddings, texts, metadata):
    from langchain.docstore.document import Document
    documents = [Document(page_content=text, metadata=meta) for text, meta in zip(texts, metadata)]
    return FAISS.from_documents(documents, embeddings)

def create_qa_chain(vector_store):
    # Set up the pipeline with a model suitable for your task
    hf_pipeline = pipeline("text2text-generation", model="model-identifier-for-llama", tokenizer="model-identifier-for-llama")
    llm = HuggingFacePipeline(pipeline=hf_pipeline)
    retriever = vector_store.as_retriever()
    return RetrievalQA.from_chain_type(llm=llm, retriever=retriever)

@app.route("/")
def home():
    return render_template("index.html")

@app.route("/ask", methods=["POST"])
def ask_question():
    question = request.json["question"]
    response = qa_chain.invoke({"query": question})  # Use "query" as input key
    return jsonify({"answer": response})

@app.route("/load_url", methods=["POST"])
def load_url():
    url = request.json["url"]
    loader = WebBaseLoader(web_paths=[url])  # Load content from the URL
    docs = loader.load()  # Load documents from the URL
    texts = [doc.page_content for doc in docs]
    metadata = [{"source": url} for _ in texts]

    embeddings = generate_embeddings()
    vector_store = create_vector_store(embeddings, texts, metadata)
    global qa_chain  # Make qa_chain accessible globally
    qa_chain = create_qa_chain(vector_store)  # Create a new QA chain with the new vector store
    return jsonify({"message": "URL content loaded successfully."})

if __name__ == "__main__":
    app.run(host="0.0.0.0", port=5055)
```

